INSERT INTO guests (order_code, full_name, role, country, ticket_type, hotel, check_in_date, check_out_date)
SELECT cf.order_code, cf.full_name, cf.role, cf.country, cf.ticket_type, cf.hotel, cf.check_in_date, cf.check_out_date
FROM csv_full cf
WHERE NOT EXISTS (SELECT 1 FROM guests g WHERE g.order_code = cf.order_code)
RETURNING order_code, full_name, ticket_type, hotel;
